// Retornar dados como array direto (compatibilidade Flask)
const result = $input.first().json;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'get_update_extension_service_data',
  event: 'data_retrieved',
  count: result.length,
  level: 'info'
}));

// CRÍTICO: Retornar array direto, não objeto encapsulado
// Para compatibilidade com a extensão
return {
  statusCode: 200,
  body: result
};

// Erro de banco
const errData = $input.first().json;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'get_update_extension_service_data',
  event: 'db_error',
  message: errData.message || 'Unknown DB error',
  level: 'error'
}));

return {
  statusCode: 500,
  body: { ok: false, error: 'Database error', message: 'Could not retrieve service data' }
};
